// Ref: #/components/schemas/creditNoteLineResult
type CreditNoteLineResult struct {
	// Field is similar to vatType, it defaults to the product's income account. Either the line or the
	// product needs to have an income account set.
	IncomeAccount OptString `json:"incomeAccount"`
	// One of: {"HIGH", "MEDIUM", "LOW", "EXEMPT", "EXEMPT_IMPORT_EXPORT", "EXEMPT_REVERSE", "OUTSIDE",
	// "NONE"}. "HIGH" is the most common.
	VatType OptString `json:"vatType"`
	// Net price per unit in invoice currency (in cents).
	UnitPrice int64 `json:"unitPrice"`
	// Number of units to be invoiced.
	Quantity float64 `json:"quantity"`
	// If field is set, all amounts must be given before the discount is applied. The API will calculate
	// the new totals. Discount value should be a percent with a value between 0 and 100. Decimal values
	// such as 25.5 are also allowed.
	Discount OptFloat64 `json:"discount"`
	// Product Id of product associated with invoice line.
	ProductId OptInt64 `json:"productId"`
	// Description of the invoiced product or service.
	Description OptString `json:"description"`
	// Additional information to be printed on invoice.
	Comment OptString `json:"comment"`
}

