// Ref: #/components/schemas/creditNoteResult
type CreditNoteResult struct {
	// Id of credit note.
	CreditNoteId int64 `json:"creditNoteId"`
	// Unique credit note number generated by us.
	CreditNoteNumber int64 `json:"creditNoteNumber"`
	// Norwegian KID number. Number from 2 to 25 digits long.
	Kid      OptString `json:"kid"`
	Customer Contact   `json:"customer"`
	// Net amount (in creditNote currency) in cents.
	Net int64 `json:"net"`
	// VAT amount (in creditNote currency) in cents.
	Vat int64 `json:"vat"`
	// Gross amount (= net+VAT) (in creditNote currency) in cents.
	Gross int64 `json:"gross"`
	// Net amount in NOK (in cents).
	NetInNok int64 `json:"netInNok"`
	// VAT amount in NOK (in cents).
	VatInNok int64 `json:"vatInNok"`
	// Gross amount in NOK (in cents).
	GrossInNok int64 `json:"grossInNok"`
	// Comment/description printed above the credit note lines.
	CreditNoteText OptString `json:"creditNoteText"`
	YourReference  OptString `json:"yourReference"`
	OurReference   OptString `json:"ourReference"`
	// Reference if sending via EHF.
	OrderReference OptString           `json:"orderReference"`
	Address        Address             `json:"address"`
	Lines          []InvoiceLineResult `json:"lines"`
	// ISO 4217 currency code.
	Currency OptString `json:"currency"`
	// Issue date of the credit note, format yyyy-mm-dd.
	IssueDate OptDate `json:"issueDate"`
	// Date that the credit note was last modified in Fiken, format yyyy-mm-dd.
	LastModifiedDate OptDate `json:"lastModifiedDate"`
	// If the credit note as been marked as settled (True) or not (False).
	Settled OptBool `json:"settled"`
	// Id of associated invoice.
	AssociatedInvoiceId OptInt64 `json:"associatedInvoiceId"`
	// The UUID of the credit note draft used to create the credit note.
	// Credit notes created directly from invoices (POST / creditNotes/full and POST /creditNotes/partial)
	// will not have a draft uuid as no draft is created in this case.
	CreditNoteDraftUuid OptString        `json:"creditNoteDraftUuid"`
	CreditNotePdf       OptAttachment    `json:"creditNotePdf"`
	Project             OptProjectResult `json:"project"`
	Sale                OptSaleResult    `json:"sale"`
}

