// doesn't know the dispatch method.
// Only possible dispatch types for offer are email, sms, or letter.
type DispatchResultDispatchType string

const (
	DispatchResultDispatchTypeEmail    DispatchResultDispatchType = "email"
	DispatchResultDispatchTypeSMS      DispatchResultDispatchType = "sms"
	DispatchResultDispatchTypeEhf      DispatchResultDispatchType = "ehf"
	DispatchResultDispatchTypeLetter   DispatchResultDispatchType = "letter"
	DispatchResultDispatchTypeVipps    DispatchResultDispatchType = "vipps"
	DispatchResultDispatchTypeEfaktura DispatchResultDispatchType = "efaktura"
	DispatchResultDispatchTypeUnknown  DispatchResultDispatchType = "unknown"
)

// AllValues returns all DispatchResultDispatchType values.
func (DispatchResultDispatchType) AllValues() []DispatchResultDispatchType {
	return []DispatchResultDispatchType{
		DispatchResultDispatchTypeEmail,
		DispatchResultDispatchTypeSMS,
		DispatchResultDispatchTypeEhf,
		DispatchResultDispatchTypeLetter,
		DispatchResultDispatchTypeVipps,
		DispatchResultDispatchTypeEfaktura,
		DispatchResultDispatchTypeUnknown,
	}
}

// MarshalText implements encoding.TextMarshaler.
func (s DispatchResultDispatchType) MarshalText() ([]byte, error) {
	switch s {
	case DispatchResultDispatchTypeEmail:
		return []byte(s), nil
	case DispatchResultDispatchTypeSMS:
		return []byte(s), nil
	case DispatchResultDispatchTypeEhf:
		return []byte(s), nil
	case DispatchResultDispatchTypeLetter:
		return []byte(s), nil
	case DispatchResultDispatchTypeVipps:
		return []byte(s), nil
	case DispatchResultDispatchTypeEfaktura:
		return []byte(s), nil
	case DispatchResultDispatchTypeUnknown:
		return []byte(s), nil
	default:
		return nil, errors.Errorf("invalid value: %q", s)
	}
}

// UnmarshalText implements encoding.TextUnmarshaler.
func (s *DispatchResultDispatchType) UnmarshalText(data []byte) error {
	switch DispatchResultDispatchType(data) {
	case DispatchResultDispatchTypeEmail:
		*s = DispatchResultDispatchTypeEmail
		return nil
	case DispatchResultDispatchTypeSMS:
		*s = DispatchResultDispatchTypeSMS
		return nil
	case DispatchResultDispatchTypeEhf:
		*s = DispatchResultDispatchTypeEhf
		return nil
	case DispatchResultDispatchTypeLetter:
		*s = DispatchResultDispatchTypeLetter
		return nil
	case DispatchResultDispatchTypeVipps:
		*s = DispatchResultDispatchTypeVipps
		return nil
	case DispatchResultDispatchTypeEfaktura:
		*s = DispatchResultDispatchTypeEfaktura
		return nil
	case DispatchResultDispatchTypeUnknown:
		*s = DispatchResultDispatchTypeUnknown
		return nil
	default:
		return errors.Errorf("invalid value: %q", data)
	}
}

