// Ref: #/components/schemas/invoiceResult
type InvoiceResult struct {
	// Invoice Id.
	InvoiceId OptInt64 `json:"invoiceId"`
	// Date that the invoice was created in Fiken, format yyyy-mm-dd.
	CreatedDate OptDate `json:"createdDate"`
	// Date that invoices was last modified in Fiken, format yyyy-mm-dd.
	LastModifiedDate OptDate `json:"lastModifiedDate"`
	// Unique invoice number generated by us.
	InvoiceNumber OptInt64 `json:"invoiceNumber"`
	// Norwegian KID number. Number from 2 to 25 digits long.
	Kid OptString `json:"kid"`
	// Issue date of the invoice, format yyyy-mm-dd.
	IssueDate OptDate `json:"issueDate"`
	// Due date of the invoice, format yyyy-mm-dd.
	DueDate OptDate `json:"dueDate"`
	// Original due date of the invoice if the due date has been changed, format yyyy-mm-dd.
	OriginalDueDate OptDate `json:"originalDueDate"`
	// Net amount (in invoice currency) in cents.
	Net OptInt64 `json:"net"`
	// VAT amount (in invoice currency) in cents.
	Vat OptInt64 `json:"vat"`
	// Gross amount (= net+VAT) (in invoice currency) in cents.
	Gross OptInt64 `json:"gross"`
	// Net amount in NOK (in cents).
	NetInNok OptInt64 `json:"netInNok"`
	// VAT amount in NOK (in cents).
	VatInNok OptInt64 `json:"vatInNok"`
	// Gross amount in NOK (in cents).
	GrossInNok OptInt64 `json:"grossInNok"`
	// Purchase associated with Invoice is a cash purchase.
	Cash OptBool `json:"cash"`
	// Comment/description printed above the invoice lines.
	InvoiceText    OptString `json:"invoiceText"`
	YourReference  OptString `json:"yourReference"`
	OurReference   OptString `json:"ourReference"`
	OrderReference OptString `json:"orderReference"`
	// The UUID of invoice draft used to create the invoice.
	InvoiceDraftUuid OptString           `json:"invoiceDraftUuid"`
	Address          OptAddress          `json:"address"`
	Lines            []InvoiceLineResult `json:"lines"`
	// ISO 4217 currency code, default value is NOK.
	Currency          OptString `json:"currency"`
	BankAccountNumber OptString `json:"bankAccountNumber"`
	// If the invoice was not sent using Fiken this can be set to "true".
	SentManually OptBool       `json:"sentManually"`
	InvoicePdf   OptAttachment `json:"invoicePdf"`
	// Associated credit note Id(s).
	AssociatedCreditNotes []int64          `json:"associatedCreditNotes"`
	Attachments           []Attachment     `json:"attachments"`
	Customer              OptContact       `json:"customer"`
	Sale                  OptSaleResult    `json:"sale"`
	Project               OptProjectResult `json:"project"`
	Dispatches            []DispatchResult `json:"dispatches"`
}

