// Ref: #/components/schemas/offer
type Offer struct {
	// Offer ID.
	OfferId OptInt64 `json:"offerId"`
	// UUID are represented as 32 hexadecimal (base-16) digits, displayed in 5 groups separated by
	// hyphens, in the form 8-4-4-4-12 for a total of 36 characters.
	OfferDraftUuid OptString `json:"offerDraftUuid"`
	// Date for offer.
	Date OptDate `json:"date"`
	// Unique offer number generated by us.
	OfferNumber OptInt32 `json:"offerNumber"`
	// Net amount (in invoice currency) in cents.
	Net OptInt64 `json:"net"`
	// VAT amount (in invoice currency) in cents.
	Vat OptInt64 `json:"vat"`
	// Gross amount (= net+VAT) (in invoice currency) in cents.
	Gross OptInt64 `json:"gross"`
	// Comment/description.
	Comment       OptString `json:"comment"`
	YourReference OptString `json:"yourReference"`
	OurReference  OptString `json:"ourReference"`
	// Reference if sending invoice via EHF.
	OrderReference OptString `json:"orderReference"`
	// The discount amount in the specified currency.
	Discount OptFloat64          `json:"discount"`
	Address  OptAddress          `json:"address"`
	Lines    []InvoiceLineResult `json:"lines"`
	// ISO 4217 currency code, default value is NOK.
	Currency OptString `json:"currency"`
	// Contact associated with offer.
	ContactId OptInt64 `json:"contactId"`
	// Contact person associated with offer. Must belong to the provided contact.
	ContactPersonId OptInt64 `json:"contactPersonId"`
	ProjectId       OptInt64 `json:"projectId"`
	// If order confirmation has been archived or not.
	Archived OptBool `json:"archived"`
	// Date that the offer was accepted. If null, the offer has not been accepted.
	Accepted   OptDate          `json:"accepted"`
	Dispatches []DispatchResult `json:"dispatches"`
}

